+/// Check if we have network access (for tests that need GitHub API)
+fn has_network() -> bool {
+    Command::new("curl")
+        .args(["-fsSL", "--connect-timeout", "5", "https://api.github.com"])
+        .stdout(Stdio::null())
+        .stderr(Stdio::null())
+        .status()
+        .is_ok_and(|s| s.success())
+}
